              display: "grid",
              gridTemplateColumns: "1fr 1fr 1fr",
              gap: "6px",
              marginTop: "10px",
            }}
          >
            {PLOTS.map((p: string) => (
              <div
                key={p}
                style={{
                  background: S.card,
                  borderRadius: "6px",
                  padding: "6px",
                  border: "1px solid " + S.border,
                }}
              >
                <div style={{ fontSize: "10px", color: S.dim }}>{p}</div>
                <div
                  style={{
                    fontSize: "12px",
                    color: pColor(p),
                    fontWeight: 700,
                  }}
                >
                  {invResult[p].totalProd.toLocaleString()}/s
                </div>
              </div>
            ))}
          </div>
        </div>
        {PLOTS.map(renderPlot)}
      </div>
    );
  };

  // ── Compare Tab ──
  const CompareTab = () => {
    const m1 = machines.large[parseInt(compFrom)] || machines.large[0];
    const m2 = machines.large[parseInt(compTo)] || machines.large[1];
    const prod1 = m1.base * compPlot,
      prod2 = m2.base * compPlot,
      gain = prod2 - prod1;
    const effectiveRate = (parseFloat(sellRate) || 15) * boostMultiplier;
    const gasForUpgrade = m2.cost / effectiveRate;
    const timeForUpgrade =
      (parseFloat(production) || 1) > 0
        ? gasForUpgrade / (parseFloat(production) || 1)
        : 0;
    const roiSeconds =
      gain > 0 && effectiveRate > 0 ? m2.cost / (gain * effectiveRate) : 0;
    return (
      <div style={{ display: "flex", flexDirection: "column", gap: "14px" }}>
        {heading("Compare Machines")}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: "10px",
          }}
        >
          <div>
            <div style={labelStyle}>Current</div>
            <select
              value={compFrom}
              onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setCompFrom(e.target.value)}
              style={{ ...inputStyle, cursor: "pointer" }}
            >
              {machines.large.map((m: typeof machines.large[0], i: number) => (
                <option key={i} value={i}>
                  {m.name}
                </option>
              ))}
            </select>
          </div>
          <div>
            <div style={labelStyle}>Upgrade</div>
            <select
              value={compTo}
              onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setCompTo(e.target.value)}
              style={{ ...inputStyle, cursor: "pointer" }}
            >
              {machines.large.map((m: typeof machines.large[0], i: number) => (
                <option key={i} value={i}>
                  {m.name}
                </option>
              ))}
            </select>
          </div>
        </div>
        <div>
          <div style={labelStyle}>Plot</div>
          <div style={{ display: "flex", gap: "6px" }}>
            {[1, 2, 3].map((m: number) =>
              pillBtn(m + "x", compPlot === m, () => setCompPlot(m))
            )}
          </div>
        </div>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: "10px",
          }}
        >
          <div
            style={{
              background: S.card,
              border: "1px solid " + S.border,
              borderRadius: "10px",
              padding: "14px",
              textAlign: "center",
            }}
          >
            <div style={{ fontSize: "11px", color: S.dim }}>{m1.name}</div>
            <div style={{ fontSize: "20px", color: S.text, fontWeight: 700 }}>
              {prod1.toLocaleString()}/s
            </div>
            <div style={{ fontSize: "12px", color: S.dim }}>{m1.costLabel}</div>
          </div>
          <div
            style={{
              background: S.hl,
              border: "1px solid " + S.accent,
              borderRadius: "10px",
              padding: "14px",
              textAlign: "center",
            }}
          >
            <div style={{ fontSize: "11px", color: S.accent }}>{m2.name}</div>
            <div style={{ fontSize: "20px", color: S.accent, fontWeight: 700 }}>
              {prod2.toLocaleString()}/s
            </div>
            <div style={{ fontSize: "12px", color: S.dim }}>{m2.costLabel}</div>
          </div>
        </div>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: "8px",
          }}
        >
          {statBox(
            "Gain",
            "+" + gain.toLocaleString() + "/s",
            gain > 0 ? S.green : S.red
          )}
          {statBox("Cost", "£" + formatNum(m2.cost))}
        </div>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: "8px",
          }}
        >
          {statBox("Time to Buy", formatTime(timeForUpgrade), S.blue)}
          {statBox("ROI Payback", formatTime(roiSeconds), S.accent)}
        </div>
        {gain > 0 && roiSeconds > 0 && (
          <div
            style={{
              fontSize: "12px",
              color: S.dim,
              textAlign: "center",
              fontStyle: "italic",
            }}
          >
            Upgrade pays for itself in {formatTime(roiSeconds)} of extra
            production
          </div>
        )}
      </div>
    );
  };

  const clearAllData = (): void => {
    if (!confirm("Reset all saved data? This clears everything.")) return;
    Object.keys(localStorage)
      .filter((k: string) => k.startsWith(LS_PREFIX))
      .forEach((k: string) => localStorage.removeItem(k));
    window.location.reload();
  };

  // ── Formulas Tab ──
  const FormulasTab = () => (
    <div style={{ display: "flex", flexDirection: "column", gap: "14px" }}>
      {heading("Formulas")}
            {formulasList.map((f: typeof formulasList[0], i: number) => (
        <div
          key={i}
          style={{
            padding: "12px",
            background: S.card,
            border: "1px solid " + S.border,
            borderRadius: "10px",
          }}
        >
          <div
            style={{
              fontSize: "13px",
              color: S.gold,
              fontWeight: 700,
              marginBottom: "4px",
            }}
          >
            {f.name}
          </div>
          <div
            style={{
              fontSize: "13px",
              color: S.blue,
              fontFamily: "monospace",
              marginBottom: "4px",
            }}
          >
            {f.formula}
          </div>
          <div style={{ fontSize: "11px", color: S.dim }}>{f.example}</div>
        </div>
      ))}
      <div
        style={{
          marginTop: "10px",
          paddingTop: "14px",
          borderTop: "1px solid " + S.border,
        }}
      >
        <button
          onClick={clearAllData}
          style={{
            padding: "10px 20px",
            borderRadius: "8px",
            fontSize: "12px",
            fontWeight: 600,
            cursor: "pointer",
            border: "1px solid " + S.red,
            background: "transparent",
            color: S.red,
            width: "100%",
          }}
        >
          Reset All Saved Data
        </button>
        <div
          style={{
            fontSize: "11px",
            color: S.dim,
            textAlign: "center",
            marginTop: "4px",
          }}
        >
          Clears calculator, inventory, targets, and theme
        </div>
      </div>
    </div>
  );

  // Close theme picker on outside click
  const themeRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (!showThemes) return;
    const handler = (e: MouseEvent) => {
      if (themeRef.current && !themeRef.current.contains(e.target as Node))
        setShowThemes(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, [showThemes]);

  const renderTab: Record<string, () => JSX.Element> = {
    Calc: CalcTab,
    Inventory: InventoryTab,
    Compare: CompareTab,
    Formulas: FormulasTab,
  };

  return (
    <div
      style={{
        background: S.bg,
        minHeight: "100vh",
        fontFamily: "'Segoe UI',system-ui,sans-serif",
      }}
    >
      <div style={{ position: "sticky", top: 0, zIndex: 50 }}>
        <div
          style={{
            background: S.hdr,
            borderBottom: "1px solid " + S.border,
            padding: "14px 16px 10px",
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <div
            style={{
              fontSize: "18px",
              fontWeight: 800,
              color: S.gold,
              fontStyle: "italic",
            }}
          >
            Crude Gains
          </div>
          <div style={{ position: "relative" }} ref={themeRef}>
            <button
              onClick={() => setShowThemes(!showThemes)}
              style={{
                padding: "6px 14px",
                borderRadius: "8px",
                fontSize: "13px",
                cursor: "pointer",
                border: "1px solid " + S.border,
                background: S.card,
                color: S.text,
              }}
            >
              {themes[theme]?.emoji || "\u{1F338}"}
            </button>
            {showThemes && (
              <div
                style={{
                  position: "absolute",
                  right: 0,
                  top: "100%",
                  marginTop: "4px",
                  background: S.card,
                  border: "1px solid " + S.border,
                  borderRadius: "10px",
                  padding: "6px",
                  zIndex: 100,
                  boxShadow: "0 4px 12px rgba(0,0,0,0.15)",
                  minWidth: "140px",
                }}
              >
                {Object.entries(themes).map(([k, v]: [string, typeof themes[keyof typeof themes]]) => (
                  <button
                    key={k}
                    onClick={() => {
                      setTheme(k);
                      setShowThemes(false);
                    }}
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: "8px",
                      width: "100%",
                      padding: "8px 10px",
                      borderRadius: "6px",
                      border: "none",
                      background: theme === k ? S.hl : "transparent",
                      color: S.text,
                      cursor: "pointer",
                      fontSize: "13px",
                      fontWeight: theme === k ? 700 : 400,
                      textAlign: "left",
                    }}
                  >
                    <span>{v.emoji}</span>
                    <span>{v.name}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
        <div
          style={{
            display: "flex",
            gap: "3px",
            padding: "8px 10px",
            overflowX: "auto",
            borderBottom: "1px solid " + S.border,
            background: S.nav,
          }}
        >
            {TABS.map((t: string) => (
            <button
              key={t}
              onClick={() => setTab(t)}
              style={{
                padding: "6px 9px",
                borderRadius: "6px",
                fontSize: "11px",
                fontWeight: 700,
                fontStyle: "italic",
                cursor: "pointer",
                whiteSpace: "nowrap",
                border: "none",
                background: tab === t ? S.hl : "transparent",
                color: tab === t ? S.accent : S.dim,
              }}
            >
              {t}
            </button>
          ))}
        </div>
      </div>
      <div style={{ padding: "16px", maxWidth: "560px", margin: "0 auto" }}>
        {(renderTab[tab] || CalcTab)()}
      </div>
    </div>
  );
}
